        }
        tr:hover {
            background-color: #f1f1f1;
        }
        .error-message {
            color: red;
            margin-top: 10px;
            font-weight: bold;
        }
    </style>
</head>
<body>
    <h1>CSV to HTML Table Converter</h1>

    <p>Paste your CSV data below and click "Parse CSV" to see it as an HTML table.</p>

    <textarea id="csvInput" placeholder="Paste your CSV data here...
Example:
Header1,Header2,Header3
DataA,"DataB with, comma",DataC
"DataD with ""quotes""",DataE,DataF
Row4Col1,Row4Col2
"></textarea>

    <button id="parseButton">Parse CSV</button>

    <div id="outputTableContainer">
        <p id="errorMessage" class="error-message" style="display: none;"></p>
        <div id="tableOutput">
            <!-- Parsed table will be inserted here -->
        </div>
    </div>

    <script>
        document.getElementById('parseButton').addEventListener('click', parseCSV);

        function parseCSV() {
            const csvText = document.getElementById('csvInput').value;
            const tableOutputDiv = document.getElementById('tableOutput');
            const errorMessageDiv = document.getElementById('errorMessage');

            tableOutputDiv.innerHTML = ''; // Clear previous table
            errorMessageDiv.style.display = 'none'; // Hide previous error

            if (!csvText.trim()) {
                errorMessageDiv.textContent = 'Please paste some CSV data into the textarea.';
                errorMessageDiv.style.display = 'block';
                return;
            }

            try {
                const parsedData = parseCSVString(csvText);
                if (parsedData.length === 0) {
                    errorMessageDiv.textContent = 'No data found after parsing. The CSV might be empty or malformed.';
                    errorMessageDiv.style.display = 'block';
                    return;
                }
                renderTable(parsedData, tableOutputDiv);
            } catch (e) {
                errorMessageDiv.textContent = 'Error parsing CSV: ' + e.message;
                errorMessageDiv.style.display = 'block';
                console.error('CSV parsing error:', e);
            }
        }

        // --- Core CSV Parsing Logic ---
        function parseCSVString(csvString) {
            const rows = [];
            let currentRow = [];
            let inQuote = false;
            let field = '';

            for (let i = 0; i < csvString.length; i++) {
                const char = csvString[i];
                const nextChar = csvString[i + 1];

                if (char === '"') {
                    if (inQuote && nextChar === '"') { // Escaped double quote
                        field += '"';
                        i++; // Skip the next quote
                    } else {
                        inQuote = !inQuote;
                    }
                } else if (char === ',' && !inQuote) {
                    currentRow.push(field);
                    field = '';
                } else if (char === '\n' && !inQuote) {
                    // Handle Windows line endings (\r\n) by checking for \r before \n
                    if (csvString[i - 1] === '\r') {
                        // This \n is part of \r\n, so we've already processed the field before \r
                    } else {
                        currentRow.push(field);
                        rows.push(currentRow);
                        currentRow = [];
                        field = '';
                    }
                } else if (char === '\r' && !inQuote) { // Handle Mac/Windows line endings
                    currentRow.push(field);
                    rows.push(currentRow);
                    currentRow = [];
                    field = '';
                    // If it's a \r\n sequence, the \n will be skipped by the next iteration
                    if (nextChar === '\n') {
                        i++;
                    }
                } else {
                    field += char;
                }
            }

            // Push the last field and row if any
            currentRow.push(field);
            if (currentRow.some(val => val !== '')) { // Only push if the row isn't entirely empty
                rows.push(currentRow);
            }

            // Filter out any completely empty rows that might result from extra newlines
            return rows.filter(row => row.length > 0 && row.some(cell => cell.trim() !== ''));
        }

        // --- Table Rendering Logic ---
        function renderTable(data, containerElement) {
            if (data.length === 0) {
                containerElement.innerHTML = '<p>No data to display.</p>';
                return;
            }

            const table = document.createElement('table');
            const thead = document.createElement('thead');
            const tbody = document.createElement('tbody');

            // Determine max columns for consistent header/body rendering
            let maxCols = 0;
            data.forEach(row => {
                if (row.length > maxCols) {
                    maxCols = row.length;
                }
            });

            // If the first row is likely a header, use it. Otherwise, generate generic headers.
            const hasHeader = true; // For simplicity, we'll assume the first row is always a header
            let headerRowData = data[0];
            let bodyData = data.slice(1);

            // Create header row
            const headerTr = document.createElement('tr');
            headerRowData.forEach(headerText => {
                const th = document.createElement('th');
                th.textContent = headerText;
                headerTr.appendChild(th);
            });
            // Fill any missing header cells if subsequent rows have more columns
            for (let i = headerRowData.length; i < maxCols; i++) {
                const th = document.createElement('th');
                th.textContent = `Column ${i + 1}`; // Generic header for extra columns
                headerTr.appendChild(th);
            }
            thead.appendChild(headerTr);
            table.appendChild(thead);

            // Create body rows
            bodyData.forEach(rowData => {
                const tr = document.createElement('tr');
                // Ensure all rows have at least maxCols cells for consistent rendering
                for (let i = 0; i < maxCols; i++) {
                    const td = document.createElement('td');
                    td.textContent = rowData[i] !== undefined ? rowData[i] : ''; // Handle missing cells
                    tr.appendChild(td);
                }
                tbody.appendChild(tr);
            });
            table.appendChild(tbody);

            containerElement.appendChild(table);
        }
    </script>
</body>
</html>
```

### How to use it:

1.  **Save the code:** Copy and paste the entire code block into a new text file.
2.  **Name it:** Save the file with an `.html` extension (e.g., `csv_parser.html`).
3.  **Open in browser:** Open the `csv_parser.html` file with your web browser.
4.  **Paste CSV:** Paste your CSV data into the large text area.
5.  **Click:** Click the "Parse CSV" button.
6.  **See the table:** The parsed data will appear as a styled HTML table below the button.

### Key Features and How they are handled:

*   **Self-contained:** All HTML, CSS, and JavaScript are in a single file.
*   **Textarea for input:** A `<textarea>` is provided for easy pasting.
*   **Parse button:** Triggers the parsing and rendering.
*   **Styled table:**
    *   `border-collapse` for clean borders.
    *   `border: 1px solid #ddd;` for clear cell borders.
    *   `tr:nth-child(even)` for alternating row colors (`#f9f9f9`).
    *   `th` elements for distinct headers.
    *   Hover effect on rows.
*   **Quoted fields containing commas:** The `parseCSVString` function uses a `inQuote` flag to correctly identify commas that are part of a field versus those that are delimiters.
*   **Escaped quotes within fields:** It handles `""` inside a quoted field as a single literal `"` character.
*   **Varying column counts across rows:**
    *   The `renderTable` function first determines `maxCols`, the maximum number of columns found in any row.
    *   It then ensures that all header cells and body cells are rendered up to `maxCols`, filling in empty strings for missing data in shorter rows. This keeps the table structure consistent.
*   **Error Handling:** Basic error messages are displayed if the textarea is empty or if a parsing error occurs.
*   **Line Endings:** Handles common line endings (`\n`, `\r`, `\r\n`).

