                        } else {
                            currentField += char;
                            currentIndex++;
                        }
                    }

                    // Add the last field of the row if not ended by comma/newline
                    if (currentField !== '' || (currentIndex === csvString.length && row.length === 0)) {
                         row.push(currentField);
                    }

                    // Only add non-empty rows
                    if (row.length > 0 && !(row.length === 1 && row[0] === '')) {
                        rows.push(row);
                    }
                }

                if (rows.length === 0) {
                    return '<p class="info">No valid CSV data found to parse.</p>';
                }

                // Determine the maximum number of columns for consistent table structure
                const maxCols = rows.reduce((max, r) => Math.max(max, r.length), 0);

                let tableHtml = '<table>';

                // Add header row (using the first row's data if available)
                if (rows.length > 0) {
                    tableHtml += '<thead><tr>';
                    rows[0].forEach(header => {
                        tableHtml += `<th>${escapeHtml(header)}</th>`;
                    });
                    // Fill missing headers if first row has fewer columns than maxCols
                    for (let i = rows[0].length; i < maxCols; i++) {
                        tableHtml += `<th>Column ${i + 1}</th>`;
                    }
                    tableHtml += '</tr></thead><tbody>';

                    // Add data rows, starting from the second row
                    for (let i = 1; i < rows.length; i++) {
                        const rowData = rows[i];
                        tableHtml += '<tr>';
                        for (let j = 0; j < maxCols; j++) {
                            const cellData = rowData[j] !== undefined ? rowData[j] : ''; // Handle missing columns
                            tableHtml += `<td>${escapeHtml(cellData)}</td>`;
                        }
                        tableHtml += '</tr>';
                    }
                } else {
                    tableHtml += '<tbody>'; // No header, just body
                }

                tableHtml += '</tbody></table>';
                return tableHtml;
            }

            /**
             * Escapes HTML entities in a string to prevent XSS.
             * @param {string} text The string to escape.
             * @returns {string} The escaped string.
             */
            function escapeHtml(text) {
                const map = {
                    '&': '&amp;',
                    '<': '&lt;',
                    '>': '&gt;',
                    '"': '&quot;',
                    "'": '&#039;'
                };
                return text.replace(/[&<>"']/g, function(m) { return map[m]; });
            }
        });
    </script>
